   153→        const DESTROYED = 1 << 0;
   154→        const AIRBORNE_TARGET = 1 << 1;
   155→        const UNSELECTABLE = 1 << 2;
   156→        const UNDER_CONSTRUCTION = 1 << 3;
   157→        const REPAIR_DEPOT_AUTO_HEALING = 1 << 4;
   158→        const PARACHUTING = 1 << 5;
   159→        const IS_FIRING_WEAPON = 1 << 6;
   160→        const INSIDE_GARRISON = 1 << 7;
   161→        const GRABBED = 1 << 8;
   162→        const BEING_REPAIRED = 1 << 9;
   163→        const IS_BRAKING = 1 << 10;
   164→        const IS_ACCELERATING = 1 << 11;
   165→        const ATTACKING = 1 << 12;
   166→        const MOVING = 1 << 13;
   167→        const USING_ABILITY = 1 << 14;
   168→        const NO_COLLISIONS = 1 << 15;
   169→        const IMMOBILE = 1 << 16;
   170→        const STEALTHED = 1 << 17;
   171→        const DETECTED = 1 << 18;
   172→        const POWERED = 1 << 19;
   173→        const IS_SELLING = 1 << 20;
   174→        const DISGUISED = 1 << 21;
   175→        const REASSIGNED_FROM_FOUNDATION = 1 << 22;
   176→        const BOOBY_TRAPPED = 1 << 23;
   177→        const SABOTAGED = 1 << 24;
   178→        const OCCUPIED = 1 << 25;
   179→        const ON_POSITION_FOR_HIJACK = 1 << 26;
   180→        const SCORE_DESTROY = 1 << 27;
   181→        const SCORE_CREATE = 1 << 28;
   182→        const NO_AUTO_HEAL = 1 << 29;
   183→        const TOPPLED = 1 << 30;
   184→        const RIDER1 = 1 << 31;
   185→        const MASKED = 1 << 32;
   186→        const CAN_STEALTH = 1 << 33;
   187→        const RECONSTRUCTING = 1 << 34;
   188→        const SOLD = 1 << 35;
   189→    }
   190→}
   191→
   192→impl ObjectStatusMaskType {
   193→    pub fn none() -> Self {
   194→        Self::empty()
   195→    }
   196→    
   197→    pub fn test(&self, bit: ObjectStatusTypes) -> bool {
   198→        self.contains(match bit {
   199→            ObjectStatusTypes::Destroyed => Self::DESTROYED,
   200→            ObjectStatusTypes::AirborneTarget => Self::AIRBORNE_TARGET,
   201→            ObjectStatusTypes::Unselectable => Self::UNSELECTABLE,
   202→            ObjectStatusTypes::UnderConstruction => Self::UNDER_CONSTRUCTION,
   203→            ObjectStatusTypes::Masked => Self::MASKED,
   204→            ObjectStatusTypes::CanStealth => Self::CAN_STEALTH,
   205→            ObjectStatusTypes::Reconstructing => Self::RECONSTRUCTING,
   206→            ObjectStatusTypes::Sold => Self::SOLD,
   207→        })
   208→    }
   209→    
   210→    pub fn set(&mut self, bit: ObjectStatusMaskType) {
   211→        *self |= bit;
   212→    }
   213→    
   214→    pub fn clear(&mut self, bit: ObjectStatusMaskType) {
   215→        *self &= !bit;
   216→    }
   217→}
