   241→bitflags! {
   242→    /// Disabled mask (matching C++ DisabledMaskType)
   243→    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
   244→    pub struct DisabledMaskType: u32 {
   245→        const DISABLED_UNDERPOWERED = 1 << 0;
   246→        const DISABLED_EMP = 1 << 1;
   247→        const DISABLED_HACKED = 1 << 2;
   248→        const DISABLED_SUBDUED = 1 << 3;
   249→        const DISABLED_UNMANNED = 1 << 4;
   250→        const DISABLED_FREEBIE = 1 << 5;
   251→        // Add more as needed
   252→    }
   253→}
   254→
   255→impl DisabledMaskType {
   256→    pub fn none() -> Self {
   257→        Self::empty()
   258→    }
   259→    
   260→    pub fn any(&self) -> bool {
   261→        !self.is_empty()
   262→    }
   263→    
   264→    pub fn test(&self, disabled_type: DisabledType) -> bool {
   265→        match disabled_type {
   266→            DisabledType::DisabledUnderpowered => self.contains(Self::DISABLED_UNDERPOWERED),
   267→            DisabledType::DisabledEmp => self.contains(Self::DISABLED_EMP),
   268→            DisabledType::DisabledHacked => self.contains(Self::DISABLED_HACKED),
   269→            DisabledType::DisabledSubdued => self.contains(Self::DISABLED_SUBDUED),
   270→            DisabledType::DisabledUnmanned => self.contains(Self::DISABLED_UNMANNED),
   271→            DisabledType::DisabledFreebie => self.contains(Self::DISABLED_FREEBIE),
   272→            DisabledType::DisabledAny => self.any(),
   273→        }
   274→    }
   275→    
   276→    pub fn set(&mut self, disabled_type: DisabledType) {
   277→        match disabled_type {
   278→            DisabledType::DisabledUnderpowered => *self |= Self::DISABLED_UNDERPOWERED,
   279→            DisabledType::DisabledEmp => *self |= Self::DISABLED_EMP,
   280→            DisabledType::DisabledHacked => *self |= Self::DISABLED_HACKED,
   281→            DisabledType::DisabledSubdued => *self |= Self::DISABLED_SUBDUED,
   282→            DisabledType::DisabledUnmanned => *self |= Self::DISABLED_UNMANNED,
   283→            DisabledType::DisabledFreebie => *self |= Self::DISABLED_FREEBIE,
   284→            DisabledType::DisabledAny => {}, // No-op for ANY
   285→        }
   286→    }
   287→    
   288→    pub fn clear(&mut self, disabled_type: DisabledType) {
   289→        match disabled_type {
   290→            DisabledType::DisabledUnderpowered => *self &= !Self::DISABLED_UNDERPOWERED,
   291→            DisabledType::DisabledEmp => *self &= !Self::DISABLED_EMP,
   292→            DisabledType::DisabledHacked => *self &= !Self::DISABLED_HACKED,
   293→            DisabledType::DisabledSubdued => *self &= !Self::DISABLED_SUBDUED,
   294→            DisabledType::DisabledUnmanned => *self &= !Self::DISABLED_UNMANNED,
   295→            DisabledType::DisabledFreebie => *self &= !Self::DISABLED_FREEBIE,
   296→            DisabledType::DisabledAny => *self = Self::empty(),
   297→        }
   298→    }
   299→}
